// bulkDeleteVulnerability deletes multiple Vulnerability entities by their IDs
func (r *mutationResolver) bulkDeleteVulnerability(ctx context.Context, ids []string) (*model.VulnerabilityBulkDeletePayload, error) {
	if len(ids) == 0 {
		return nil, rout.NewMissingRequiredFieldError("ids")
	}

	originalIDs := append([]string(nil), ids...)
	ids = r.filterAuthorizedIDs(ctx, ids, "vulnerability", fgax.CanDelete)
	if len(ids) == 0 {
		err := gqlerrors.BulkActionIncomplete

		return &model.VulnerabilityBulkDeletePayload{
			DeletedIDs:    []string{},
			NotDeletedIDs: originalIDs,
			Error:         &err,
		}, nil
	}

	deletedIDs := make([]string, 0, len(ids))
	errors := make([]error, 0, len(ids))

	var mu sync.Mutex

	funcs := make([]func(), 0, len(ids))
	for _, id := range ids {
		funcs = append(funcs, func() {
			// use r.db in context so interceptors use the connection pool instead of the shared transaction
			poolCtx := generated.NewContext(ctx, r.db)

			// delete each vulnerability individually to ensure proper cleanup
			if err := r.db.Vulnerability.DeleteOneID(id).Exec(poolCtx); err != nil {
				logx.FromContext(poolCtx).Error().Err(err).Str("vulnerability_id", id).Msg("failed to delete vulnerability in bulk operation")
				mu.Lock()
				errors = append(errors, err)
				mu.Unlock()
				return
			}

			if err := generated.VulnerabilityEdgeCleanup(poolCtx, id); err != nil {
				logx.FromContext(poolCtx).Error().Err(err).Str("vulnerability_id", id).Msg("failed to cleanup vulnerability edges in bulk operation")
				mu.Lock()
				errors = append(errors, err)
				mu.Unlock()
				return
			}

			mu.Lock()
			deletedIDs = append(deletedIDs, id)
			mu.Unlock()
		})
	}

	if err := r.withPool().SubmitMultipleAndWait(funcs); err != nil {
		return nil, err
	}

	if len(errors) > 0 {
		logx.FromContext(ctx).Error().Int("deleted_items", len(deletedIDs)).Int("errors", len(errors)).Msg("some vulnerability deletions failed")
	}

	deleted := make(map[string]struct{}, len(deletedIDs))
	for _, id := range deletedIDs {
		deleted[id] = struct{}{}
	}

	notDeletedIDs := make([]string, 0, len(originalIDs))
	for _, id := range originalIDs {
		if _, ok := deleted[id]; !ok {
			notDeletedIDs = append(notDeletedIDs, id)
		}
	}

	var err *string
	if len(notDeletedIDs) > 0 {
		bulkActionIncomplete := gqlerrors.BulkActionIncomplete
		err = &bulkActionIncomplete
	}

	return &model.VulnerabilityBulkDeletePayload{
		DeletedIDs:    deletedIDs,
		NotDeletedIDs: notDeletedIDs,
		Error:         err,
	}, nil
}

// bulkCreateWorkflowDefinition uses the CreateBulk function to create multiple WorkflowDefinition entities
func (r *mutationResolver) bulkCreateWorkflowDefinition(ctx context.Context, input []*generated.CreateWorkflowDefinitionInput) (*model.WorkflowDefinitionBulkCreatePayload, error) {
	c := withTransactionalMutation(ctx)
	builders := make([]*generated.WorkflowDefinitionCreate, len(input))
	for i, data := range input {
		builders[i] = c.WorkflowDefinition.Create().SetInput(*data)
	}

	res, err := c.WorkflowDefinition.CreateBulk(builders...).Save(ctx)
	if err != nil {
		return nil, parseRequestError(ctx, err, common.Action{Action: common.ActionCreate, Object: "workflowdefinition"})
	}

	// return response
	return &model.WorkflowDefinitionBulkCreatePayload{
		WorkflowDefinitions: res,
	}, nil
}
